window.BILARA = window.BILARA || {};
window.BILARA["dn19"] = window.BILARA["dn19"] || {};
window.BILARA["dn19"]["vi"] ={
  "dn19:0.1": "Trường Bộ Kinh 19 ",
  "dn19:0.2": "Kinh Đại Điển Tôn ",
  "dn19:1.1": "Tôi nghe như vầy—",
  "dn19:1.2": "Một thời, Thế Tôn trú tại Rājagaha, trên núi Gijjhakūṭa.",
  "dn19:1.3": "Bấy giờ, Pañcasikha, con trai của vị càn-thát-bà, vào lúc đêm đã gần tàn, với dung sắc rực rỡ, chiếu sáng toàn thể núi Gijjhakūṭa, đi đến chỗ Thế Tôn; sau khi đến, đảnh lễ Thế Tôn rồi đứng sang một bên. Đứng sang một bên, Pañcasikha, con trai của vị càn-thát-bà, bạch Thế Tôn rằng:",
  "dn19:1.4": "“Bạch Thế Tôn, điều gì con đã được nghe trực tiếp, được tiếp nhận trực tiếp trước mặt chư thiên cõi Tāvatiṁsa, con xin trình lên Thế Tôn.”",
  "dn19:1.5": "“Này Pañcasikha, hãy trình cho Ta nghe,” Thế Tôn nói.",
  "dn19:2.0": "1. Hội chúng chư thiên ",
  "dn19:2.1": "“Bạch Thế Tôn, vào những ngày trước đây, vào ngày bố-tát, ngày rằm, đêm trăng tròn mãn nguyệt của lễ tự tứ, toàn thể chư thiên cõi Tāvatiṁsa ngồi tụ họp trong hội trường Sudhammā;",
  "dn19:2.2": "một đại hội chư thiên đông đảo ngồi khắp chung quanh, và bốn vị Đại vương ngồi ở bốn phương;",
  "dn19:2.3": "ở phương đông, Đại vương Dhataraṭṭha ngồi quay mặt về phương tây, dẫn đầu chư thiên;",
  "dn19:2.4": "ở phương nam, Đại vương Virūḷhaka ngồi quay mặt về phương bắc, dẫn đầu chư thiên;",
  "dn19:2.5": "ở phương tây, Đại vương Virūpakkha ngồi quay mặt về phương đông, dẫn đầu chư thiên;",
  "dn19:2.6": "ở phương bắc, Đại vương Vessavaṇa ngồi quay mặt về phương nam, dẫn đầu chư thiên.",
  "dn19:2.7": "Bạch Thế Tôn, khi toàn thể chư thiên cõi Tāvatiṁsa ngồi tụ họp trong hội trường Sudhammā, khi đại hội chư thiên đông đảo ngồi khắp chung quanh, và bốn vị Đại vương ngồi ở bốn phương, thì đó là chỗ ngồi của các vị ấy;",
  "dn19:2.8": "còn chỗ ngồi của chúng con thì ở phía sau.",
  "dn19:3.1": "Bạch Thế Tôn, những vị chư thiên nào đã sống phạm hạnh dưới Thế Tôn và nay mới tái sinh vào chúng Tāvatiṁsa, thì các vị ấy vượt trội hơn các chư thiên khác cả về dung sắc lẫn danh tiếng.",
  "dn19:3.2": "Do vậy, bạch Thế Tôn, chư thiên cõi Tāvatiṁsa hoan hỷ, vui mừng, khởi lên hỷ lạc;",
  "dn19:3.3": "‘Thật vậy, các thiên chúng được tăng thêm, còn các chúng a-tu-la thì suy giảm.’",
  "dn19:3.4": "Bấy giờ, bạch Thế Tôn, Thiên chủ Sakka, vua của chư thiên, biết được niềm hoan hỷ của chư thiên cõi Tāvatiṁsa, liền tùy hỷ bằng những bài kệ này:",
  "dn19:3.5": "‘Thật vậy, chư thiên hoan hỷ,",
  "dn19:3.6": "chư Tāvatiṁsa cùng với Inda;",
  "dn19:3.7": "đảnh lễ Như Lai,",
  "dn19:3.8": "và sự chân chánh tốt đẹp của Chánh pháp.",
  "dn19:3.9": "Khi thấy những chư thiên mới,",
  "dn19:3.10": "có dung sắc đẹp, có danh tiếng;",
  "dn19:3.11": "đã sống phạm hạnh",
  "dn19:3.12": "với bậc Thiện Thệ rồi đến đây.",
  "dn19:3.13": "Họ vượt trội hơn",
  "dn19:3.14": "những chư thiên khác về dung sắc, danh tiếng và tuổi thọ;",
  "dn19:3.15": "là đệ tử của bậc đại trí,",
  "dn19:3.16": "đã đạt đến sự thù thắng ở đây.",
  "dn19:3.17": "Thấy điều ấy, họ hoan hỷ,",
  "dn19:3.18": "chư Tāvatiṁsa cùng với Inda;",
  "dn19:3.19": "đảnh lễ Như Lai,",
  "dn19:3.20": "và sự chân chánh tốt đẹp của Chánh pháp.’",
  "dn19:3.21": "Do vậy, bạch Thế Tôn, chư thiên cõi Tāvatiṁsa lại càng thêm hoan hỷ, vui mừng, khởi lên hỷ lạc;",
  "dn19:3.22": "‘Thật vậy, các thiên chúng được tăng thêm, còn các chúng a-tu-la thì suy giảm.’",
  "dn19:4.0": "2. Tám lời tán thán chân thật ",
  "dn19:4.1": "Bấy giờ, bạch Thế Tôn, Thiên chủ Sakka, vua của chư thiên, biết được niềm hoan hỷ của chư thiên cõi Tāvatiṁsa, liền nói với chư thiên cõi Tāvatiṁsa rằng:",
  "dn19:4.2": "‘Này các hiền giả, các vị có muốn nghe tám lời tán thán chân thật về Thế Tôn ấy không?’",
  "dn19:4.3": "‘Thưa hiền giả, chúng tôi muốn nghe tám lời tán thán chân thật về Thế Tôn ấy.’",
  "dn19:4.4": "Bấy giờ, bạch Thế Tôn, Thiên chủ Sakka, vua của chư thiên, đã tuyên đọc tám lời tán thán chân thật về Thế Tôn cho chư thiên cõi Tāvatiṁsa:",
  "dn19:5.1": "‘Chư thiên cõi Tāvatiṁsa nghĩ thế nào?",
  "dn19:5.2": "Thế Tôn ấy đã thực hành vì lợi ích cho số đông, vì hạnh phúc cho số đông, vì lòng thương tưởng đời, vì lợi ích, an vui cho chư thiên và loài người.",
  "dn19:5.3": "Một bậc Đạo sư đầy đủ phương diện này, thực hành vì lợi ích cho số đông, vì hạnh phúc cho số đông, vì lòng thương tưởng đời, vì lợi ích, an vui cho chư thiên và loài người như vậy, chúng ta không thấy trong thời quá khứ, cũng không thấy trong hiện tại, ngoài Thế Tôn ấy.",
  "dn19:6.1": "Hơn nữa, Chánh pháp do Thế Tôn ấy khéo thuyết là thiết thực hiện tại, không có thời gian, đến để mà thấy, có khả năng hướng thượng, được người trí tự mình giác hiểu.",
  "dn19:6.2": "Một bậc Đạo sư đầy đủ phương diện này, là người thuyết giảng một pháp có khả năng hướng thượng như vậy, chúng ta không thấy trong thời quá khứ, cũng không thấy trong hiện tại, ngoài Thế Tôn ấy.",
  "dn19:7.1": "Hơn nữa, Thế Tôn ấy đã khéo chỉ rõ: ‘Đây là thiện’, và khéo chỉ rõ: ‘Đây là bất thiện’.",
  "dn19:7.2": "‘Đây là có tội, đây là không tội; đây nên thực hành, đây không nên thực hành; đây là thấp kém, đây là cao thượng; đây là phần tương ưng với đen và trắng’, đều được khéo chỉ rõ.",
  "dn19:7.3": "Một bậc Đạo sư đầy đủ phương diện này, là người chỉ bày các pháp thiện và bất thiện, có tội và không tội, nên thực hành và không nên thực hành, thấp kém và cao thượng, tương ưng với đen và trắng như vậy, chúng ta không thấy trong thời quá khứ, cũng không thấy trong hiện tại, ngoài Thế Tôn ấy.",
  "dn19:8.1": "Hơn nữa, con đường thực hành đưa đến Niết-bàn cho các đệ tử đã được Thế Tôn ấy khéo chỉ dạy, và con đường ấy phù hợp, tương ứng với Niết-bàn.",
  "dn19:8.2": "Ví như nước sông Hằng hòa hợp, gặp gỡ với nước sông Yamunā;",
  "dn19:8.3": "cũng vậy, con đường thực hành đưa đến Niết-bàn cho các đệ tử đã được Thế Tôn ấy khéo chỉ dạy, và Niết-bàn cùng con đường ấy phù hợp với nhau.",
  "dn19:8.4": "Một bậc Đạo sư đầy đủ phương diện này, là người chỉ bày con đường đưa đến Niết-bàn như vậy, chúng ta không thấy trong thời quá khứ, cũng không thấy trong hiện tại, ngoài Thế Tôn ấy.",
  "dn19:9.1": "Hơn nữa, lợi dưỡng của Thế Tôn ấy đã thành tựu, danh tiếng đã thành tựu, đến mức các vị sát-đế-lỵ sống trong sự kính mến đối với Ngài; nhưng Thế Tôn ấy đã lìa kiêu mạn khi thọ dụng vật thực.",
  "dn19:9.2": "Một bậc Đạo sư đầy đủ phương diện này, thọ dụng vật thực mà không còn kiêu mạn như vậy, chúng ta không thấy trong thời quá khứ, cũng không thấy trong hiện tại, ngoài Thế Tôn ấy.",
  "dn19:10.1": "Hơn nữa, Thế Tôn ấy có được bạn đồng hành là các vị hữu học đang thực hành và các vị lậu tận đã sống xong phạm hạnh.",
  "dn19:10.2": "Nhưng Thế Tôn ấy gạt bỏ sự ưa thích hội chúng, sống chuyên chú vào sự an trú một mình.",
  "dn19:10.3": "Một bậc Đạo sư đầy đủ phương diện này, chuyên chú vào sự an trú một mình như vậy, chúng ta không thấy trong thời quá khứ, cũng không thấy trong hiện tại, ngoài Thế Tôn ấy.",
  "dn19:11.1": "Hơn nữa, Thế Tôn ấy nói sao làm vậy, làm sao nói vậy; như nói thế nào thì làm thế ấy, như làm thế nào thì nói thế ấy.",
  "dn19:11.2": "Một bậc Đạo sư đầy đủ phương diện này, thực hành đúng theo pháp và tùy pháp như vậy, chúng ta không thấy trong thời quá khứ, cũng không thấy trong hiện tại, ngoài Thế Tôn ấy.",
  "dn19:12.1": "Hơn nữa, Thế Tôn ấy đã vượt qua nghi hoặc, không còn phân vân, đã hoàn tất chí nguyện trong đời sống phạm hạnh từ đầu đến cuối.",
  "dn19:12.2": "Một bậc Đạo sư đầy đủ phương diện này, đã vượt qua nghi hoặc, không còn phân vân, đã hoàn tất chí nguyện trong đời sống phạm hạnh từ đầu đến cuối như vậy, chúng ta không thấy trong thời quá khứ, cũng không thấy trong hiện tại, ngoài Thế Tôn ấy.’",
  "dn19:12.3": "Bạch Thế Tôn, đó là tám lời tán thán chân thật về Thế Tôn mà Thiên chủ Sakka, vua của chư thiên, đã tuyên đọc cho chư thiên cõi Tāvatiṁsa.",
  "dn19:12.4": "Do vậy, bạch Thế Tôn, chư thiên cõi Tāvatiṁsa lại càng thêm hoan hỷ, vui mừng, khởi lên hỷ lạc khi nghe tám lời tán thán chân thật về Thế Tôn.",
  "dn19:13.1": "Khi ấy, bạch Thế Tôn, một số chư thiên nói như sau:",
  "dn19:13.2": "‘Ôi, này các hiền giả, giá như có bốn bậc Chánh Đẳng Giác xuất hiện ở đời và thuyết pháp như Thế Tôn vậy.",
  "dn19:13.3": "Điều ấy sẽ đem lại lợi ích cho số đông, hạnh phúc cho số đông, vì lòng thương tưởng đời, vì lợi ích, an vui cho chư thiên và loài người.’",
  "dn19:13.4": "Một số chư thiên khác nói như sau:",
  "dn19:13.5": "‘Thôi, này các hiền giả, bốn bậc Chánh Đẳng Giác; ôi, này các hiền giả, giá như có ba bậc Chánh Đẳng Giác xuất hiện ở đời và thuyết pháp như Thế Tôn vậy.",
  "dn19:13.6": "Điều ấy sẽ đem lại lợi ích cho số đông, hạnh phúc cho số đông, vì lòng thương tưởng đời, vì lợi ích, an vui cho chư thiên và loài người.’",
  "dn19:13.7": "Một số chư thiên khác nói như sau:",
  "dn19:13.8": "‘Thôi, này các hiền giả, ba bậc Chánh Đẳng Giác; ôi, này các hiền giả, giá như có hai bậc Chánh Đẳng Giác xuất hiện ở đời và thuyết pháp như Thế Tôn vậy.",
  "dn19:13.9": "Điều ấy sẽ đem lại lợi ích cho số đông, hạnh phúc cho số đông, vì lòng thương tưởng đời, vì lợi ích, an vui cho chư thiên và loài người.’",
  "dn19:14.1": "Khi được nói vậy, bạch Thế Tôn, Thiên chủ Sakka, vua của chư thiên, nói với chư thiên cõi Tāvatiṁsa rằng:",
  "dn19:14.2": "‘Này các hiền giả, điều ấy không thể có, không có cơ hội xảy ra, rằng trong một thế giới lại có hai bậc A-la-hán Chánh Đẳng Giác xuất hiện không trước không sau; chuyện ấy không thể có.",
  "dn19:14.3": "Ôi, này các hiền giả, mong rằng Thế Tôn ấy được ít bệnh, ít não, tồn tại lâu dài trong một thời gian dài.",
  "dn19:14.4": "Điều ấy sẽ đem lại lợi ích cho số đông, hạnh phúc cho số đông, vì lòng thương tưởng đời, vì lợi ích, an vui cho chư thiên và loài người.’",
  "dn19:14.5": "Bấy giờ, bạch Thế Tôn, vì mục đích nào mà chư thiên cõi Tāvatiṁsa ngồi tụ họp trong hội trường Sudhammā, sau khi suy nghĩ và bàn luận về mục đích ấy, thì bốn vị Đại vương cũng cùng ở trong việc ấy.",
  "dn19:14.6": "Sau khi nhận lời chỉ dạy, bốn vị Đại vương ấy cũng cùng ở trong việc ấy, đứng tại chỗ ngồi riêng của mình, không rời đi.",
  "dn19:14.7": "Các vị vua ấy, sau khi nghe lời nói,",
  "dn19:14.8": "và tiếp nhận lời giáo huấn,",
  "dn19:14.9": "với tâm hết sức trong sáng, an tịnh,",
  "dn19:14.10": "đã đứng yên tại chỗ ngồi của mình.",
  "dn19:15.1": "Bấy giờ, bạch Thế Tôn, ở phương bắc xuất hiện một luồng ánh sáng lớn, một hào quang hiện ra vượt hẳn oai lực của chư thiên.",
  "dn19:15.2": "Bấy giờ, bạch Thế Tôn, Thiên chủ Sakka, vua của chư thiên, nói với chư thiên cõi Tāvatiṁsa rằng:",
  "dn19:15.3": "‘Này các hiền giả, khi các điềm tướng như vậy xuất hiện, khi một luồng ánh sáng lớn khởi lên, khi hào quang hiện ra, thì Phạm thiên sẽ hiện đến;",
  "dn19:15.4": "vì đó là điềm báo trước cho sự hiện đến của Phạm thiên, tức là ánh sáng khởi lên và hào quang hiện ra.’",
  "dn19:15.5": "Khi các điềm tướng xuất hiện,",
  "dn19:15.6": "Phạm thiên sẽ hiện đến;",
  "dn19:15.7": "vì đó là điềm của Phạm thiên,",
  "dn19:15.8": "một hào quang rộng lớn, vĩ đại.’",
  "dn19:16.0": "3. Câu chuyện về Sanaṅkumāra ",
  "dn19:16.1": "Bấy giờ, bạch Thế Tôn, chư thiên cõi Tāvatiṁsa ngồi xuống tại chỗ ngồi riêng của mình:",
  "dn19:16.2": "‘Chúng ta sẽ biết ánh sáng này là gì, kết quả của nó sẽ ra sao; chỉ sau khi tự mình chứng kiến, chúng ta mới ra đi.’",
  "dn19:16.3": "Cả bốn vị Đại vương cũng ngồi xuống tại chỗ ngồi riêng của mình:",
  "dn19:16.4": "‘Chúng ta sẽ biết ánh sáng này là gì, kết quả của nó sẽ ra sao; chỉ sau khi tự mình chứng kiến, chúng ta mới ra đi.’",
  "dn19:16.5": "Nghe vậy, chư thiên cõi Tāvatiṁsa nhất tâm nhập định:",
  "dn19:16.6": "‘Chúng ta sẽ biết ánh sáng này là gì, kết quả của nó sẽ ra sao; chỉ sau khi tự mình chứng kiến, chúng ta mới ra đi.’",
  "dn19:16.7": "Bạch Thế Tôn, khi Phạm thiên Sanaṅkumāra hiện ra giữa chư thiên cõi Tāvatiṁsa, vị ấy hiện ra sau khi hóa hiện một thân hình thô rõ.",
  "dn19:16.8": "Nhưng, bạch Thế Tôn, sắc thân tự nhiên của Phạm thiên thì chư thiên cõi Tāvatiṁsa không thể thấy được trong tầm mắt.",
  "dn19:16.9": "Bạch Thế Tôn, khi Phạm thiên Sanaṅkumāra hiện ra giữa chư thiên cõi Tāvatiṁsa, vị ấy vượt hơn các chư thiên khác cả về dung sắc lẫn uy danh.",
  "dn19:16.10": "Ví như, bạch Thế Tôn, sắc vóc ấy vượt hơn sắc vóc loài người;",
  "dn19:16.11": "cũng vậy, bạch Thế Tôn, khi Phạm thiên Sanaṅkumāra hiện ra giữa chư thiên cõi Tāvatiṁsa, vị ấy vượt hơn các chư thiên khác cả về dung sắc lẫn uy danh.",
  "dn19:16.12": "Bạch Thế Tôn, khi Phạm thiên Sanaṅkumāra hiện ra giữa chư thiên cõi Tāvatiṁsa, trong hội chúng ấy không có vị thiên nào đảnh lễ, đứng dậy chào, hay mời chỗ ngồi đến vị ấy.",
  "dn19:16.13": "Tất cả đều im lặng, chắp tay, ngồi kiết già:",
  "dn19:16.14": "‘Hôm nay Phạm thiên Sanaṅkumāra muốn ngồi trên chỗ ngồi của vị thiên nào, thì sẽ ngồi trên chỗ ngồi của vị thiên ấy.’",
  "dn19:16.15": "Nhưng, bạch Thế Tôn, vị thiên nào được Phạm thiên Sanaṅkumāra ngồi trên chỗ ngồi của mình, vị thiên ấy đạt được cảm thọ thù thắng, đạt được hỷ lạc thù thắng.",
  "dn19:17.1": "Ví như, bạch Thế Tôn, một vị vua Sát-đế-lỵ đã được quán đảnh, vừa mới đăng quang vương quyền, vị ấy đạt được cảm thọ thù thắng, đạt được hỷ lạc thù thắng;",
  "dn19:17.2": "cũng vậy, bạch Thế Tôn, vị thiên nào được Phạm thiên Sanaṅkumāra ngồi trên chỗ ngồi của mình, vị thiên ấy đạt được cảm thọ thù thắng, đạt được hỷ lạc thù thắng.",
  "dn19:17.3": "Rồi, bạch Thế Tôn, Phạm thiên Sanaṅkumāra sau khi biết được niềm tịnh tín của chư thiên cõi Tāvatiṁsa, liền biến mất và tùy hỷ bằng những bài kệ này:",
  "dn19:17.4": "‘Thật vậy, này chư thiên, các vị hoan hỷ,",
  "dn19:17.5": "chư thiên Tāvatiṁsa cùng với Đế Thích;",
  "dn19:17.6": "đang đảnh lễ Như Lai,",
  "dn19:17.7": "và diệu pháp chân chánh của Pháp.",
  "dn19:17.8": "Thấy những vị thiên mới,",
  "dn19:17.9": "đầy dung sắc, đầy uy danh;",
  "dn19:17.10": "đã sống phạm hạnh",
  "dn19:17.11": "nơi bậc Thiện Thệ rồi đến đây.",
  "dn19:17.12": "Họ vượt hơn những vị khác,",
  "dn19:17.13": "về dung sắc, uy danh và tuổi thọ;",
  "dn19:17.14": "là đệ tử của bậc đại tuệ,",
  "dn19:17.15": "đã đạt đến sự thù thắng ở đây.",
  "dn19:17.16": "Thấy điều này, họ hoan hỷ,",
  "dn19:17.17": "chư thiên Tāvatiṁsa cùng với Đế Thích;",
  "dn19:17.18": "đang đảnh lễ Như Lai,",
  "dn19:17.19": "và diệu pháp chân chánh của Pháp.’",
  "dn19:18.1": "Bạch Thế Tôn, Phạm thiên Sanaṅkumāra đã nói ý nghĩa ấy.",
  "dn19:18.2": "Bạch Thế Tôn, khi Phạm thiên Sanaṅkumāra nói ý nghĩa ấy, âm thanh của vị ấy có đủ tám đặc tính: rõ ràng, dễ nhận biết, êm dịu, dễ nghe, tròn đầy, không rối loạn, trầm hùng và vang vọng.",
  "dn19:18.3": "Nhưng, bạch Thế Tôn, Phạm thiên Sanaṅkumāra chỉ làm cho hội chúng ấy hiểu bằng âm thanh của mình, chứ tiếng ấy không vang ra ngoài hội chúng.",
  "dn19:18.4": "Bạch Thế Tôn, người nào có âm thanh đầy đủ tám đặc tính như vậy thì được gọi là ‘phạm âm’.",
  "dn19:19.1": "Rồi, bạch Thế Tôn, chư thiên cõi Tāvatiṁsa nói với Phạm thiên Sanaṅkumāra như sau:",
  "dn19:19.2": "‘Lành thay, Đại Phạm, chính vì suy xét điều ấy mà chúng tôi hoan hỷ;",
  "dn19:19.3": "và Đế Thích, vua của chư thiên, cũng đã nói tám lời tán thán chân thật về Thế Tôn ấy;",
  "dn19:19.4": "chúng tôi cũng hoan hỷ khi suy xét những điều ấy.’",
  "dn19:19.5.0": "4. Tám lời tán thán chân thật",
  "dn19:19.6": "Rồi, bạch Thế Tôn, Phạm thiên Sanaṅkumāra nói với Đế Thích, vua của chư thiên:",
  "dn19:19.7": "‘Lành thay, Thiên chủ, chúng tôi cũng muốn được nghe tám lời tán thán chân thật ấy về Thế Tôn.’",
  "dn19:19.8": "‘Vâng, Đại Phạm,’ bạch Thế Tôn, Đế Thích, vua của chư thiên, đã tuyên đọc tám lời tán thán chân thật về Thế Tôn cho Phạm thiên Sanaṅkumāra nghe.",
  "dn19:20.1": "‘Đại Phạm nghĩ thế nào?",
  "dn19:20.2": "Cho đến mức Thế Tôn ấy thực hành vì lợi ích cho số đông, vì hạnh phúc cho số đông, vì lòng thương tưởng thế gian, vì lợi ích, an vui cho chư thiên và loài người.",
  "dn19:20.3": "Một bậc Đạo sư đầy đủ phương diện này, thực hành vì lợi ích cho số đông, vì hạnh phúc cho số đông, vì lòng thương tưởng thế gian, vì lợi ích, an vui cho chư thiên và loài người như vậy, chúng tôi không thấy trong thời quá khứ, cũng không thấy trong hiện tại, ngoài Thế Tôn ấy.",
  "dn19:21.1": "Hơn nữa, pháp do Thế Tôn ấy khéo thuyết là thiết thực hiện tại, không bị thời gian chi phối, đến để mà thấy, có khả năng hướng thượng, được người trí tự mình giác hiểu.",
  "dn19:21.2": "Một bậc Đạo sư đầy đủ phương diện này, là người thuyết giảng một pháp có khả năng hướng thượng như vậy, chúng tôi không thấy trong thời quá khứ, cũng không thấy trong hiện tại, ngoài Thế Tôn ấy.",
  "dn19:22.1": "Hơn nữa, Thế Tôn ấy đã khéo chỉ rõ: ‘Đây là thiện’, khéo chỉ rõ: ‘Đây là bất thiện’, khéo chỉ rõ: ‘Đây là có lỗi, đây là không lỗi; đây nên thực hành, đây không nên thực hành; đây là thấp kém, đây là cao thượng; đây là phần tương ứng với đen và trắng.’",
  "dn19:22.2": "Người tuyên thuyết các pháp như thiện và bất thiện, có lỗi và không lỗi, nên thực hành và không nên thực hành, thấp kém và cao thượng, tương ứng với đen và trắng như vậy,",
  "dn19:22.3": "một bậc Đạo sư đầy đủ phương diện này, chúng tôi không thấy trong thời quá khứ, cũng không thấy trong hiện tại, ngoài Thế Tôn ấy.",
  "dn19:23.1": "Hơn nữa, Thế Tôn ấy đã khéo chỉ bày cho các đệ tử con đường đưa đến Niết-bàn; con đường ấy tương ứng, phù hợp với Niết-bàn.",
  "dn19:23.2": "Ví như nước sông Hằng hòa hợp, gặp gỡ với nước sông Yamunā;",
  "dn19:23.3": "cũng vậy, con đường đưa đến Niết-bàn do Thế Tôn ấy khéo chỉ bày cho các đệ tử là tương ứng, phù hợp với Niết-bàn.",
  "dn19:23.4": "Một bậc Đạo sư đầy đủ phương diện này, là người chỉ bày con đường đưa đến Niết-bàn như vậy, chúng tôi không thấy trong thời quá khứ, cũng không thấy trong hiện tại, ngoài Thế Tôn ấy.",
  "dn19:24.1": "Hơn nữa, lợi dưỡng của Thế Tôn ấy đã thành tựu, danh tiếng đã thành tựu, đến mức các vị Sát-đế-lỵ tưởng như đều sống trong lòng kính mến đối với Ngài.",
  "dn19:24.2": "Nhưng Thế Tôn ấy dùng vật thực với tâm không kiêu mạn.",
  "dn19:24.3": "Một bậc Đạo sư đầy đủ phương diện này, dùng vật thực với tâm không kiêu mạn như vậy, chúng tôi không thấy trong thời quá khứ, cũng không thấy trong hiện tại, ngoài Thế Tôn ấy.",
  "dn19:25.1": "Hơn nữa, Thế Tôn ấy có bạn đồng hành là các vị hữu học đang thực hành và các vị lậu tận đã sống xong phạm hạnh; nhưng Thế Tôn ấy gạt bỏ họ sang một bên và sống chuyên chú trong niềm vui độc cư.",
  "dn19:25.2": "Một bậc Đạo sư đầy đủ phương diện này, chuyên chú trong niềm vui độc cư như vậy, chúng tôi không thấy trong thời quá khứ, cũng không thấy trong hiện tại, ngoài Thế Tôn ấy.",
  "dn19:26.1": "Hơn nữa, Thế Tôn ấy nói sao làm vậy, làm sao nói vậy;",
  "dn19:26.2": "nghĩa là nói sao làm vậy, làm sao nói vậy.",
  "dn19:26.3": "Một bậc Đạo sư đầy đủ phương diện này, thực hành đúng theo pháp và thuận pháp như vậy, chúng tôi không thấy trong thời quá khứ, cũng không thấy trong hiện tại, ngoài Thế Tôn ấy.",
  "dn19:27.1": "Hơn nữa, Thế Tôn ấy đã vượt qua nghi hoặc, không còn phân vân, quyết định trọn vẹn về chí hướng trong đời sống phạm hạnh từ đầu.",
  "dn19:27.2": "Một bậc như vậy, đã vượt qua nghi hoặc, không còn phân vân, quyết định trọn vẹn về chí hướng trong đời sống phạm hạnh từ đầu,",
  "dn19:27.3": "một bậc Đạo sư đầy đủ phương diện này, chúng tôi không thấy trong thời quá khứ, cũng không thấy trong hiện tại, ngoài Thế Tôn ấy.’",
  "dn19:28.1": "Bạch Thế Tôn, đó là tám lời tán thán chân thật về Thế Tôn mà Đế Thích, vua của chư thiên, đã tuyên đọc cho Phạm thiên Sanaṅkumāra.",
  "dn19:28.2": "Do vậy, bạch Thế Tôn, Phạm thiên Sanaṅkumāra hoan hỷ, vui mừng, khởi lên hân hoan và hỷ lạc khi nghe tám lời tán thán chân thật về Thế Tôn.",
  "dn19:28.3": "Rồi, bạch Thế Tôn, Phạm thiên Sanaṅkumāra hóa hiện một thân hình thô rõ, mang dáng vẻ một thiếu niên, và hiện ra giữa chư thiên cõi Tāvatiṁsa.",
  "dn19:28.4": "Vị ấy bay lên hư không rồi ngồi kiết già giữa khoảng trời.",
  "dn19:28.5": "Ví như, bạch Thế Tôn, một người lực lưỡng có thể ngồi kiết già trên một chiếc giường được trải khéo hay trên một nền đất bằng phẳng;",
  "dn19:28.6": "cũng vậy, bạch Thế Tôn, Phạm thiên Sanaṅkumāra bay lên hư không, ngồi kiết già giữa khoảng trời rồi nói với chư thiên cõi Tāvatiṁsa:",
  "dn19:28.7.0": "5. Chuyện Bà-la-môn Govinda",
  "dn19:28.8": "‘Chư vị thiên cõi Tāvatiṁsa nghĩ thế nào, Thế Tôn ấy từ lâu dài đã là bậc đại tuệ.",
  "dn19:29.1": "Này chư vị, thuở xưa có một vị vua tên là Disampati.",
  "dn19:29.2": "Vua Disampati có một vị Bà-la-môn tế sư tên là Govinda.",
  "dn19:29.3": "Vua Disampati có một người con trai tên là hoàng tử Reṇu.",
  "dn19:29.4": "Bà-la-môn Govinda có một người con trai thanh niên tên là Jotipāla.",
  "dn19:29.5": "Như vậy, hoàng tử Reṇu, thanh niên Jotipāla và sáu vị Sát-đế-lỵ khác, tất cả tám người ấy là bạn hữu.",
  "dn19:29.6": "Rồi, này chư vị, sau một thời gian, Bà-la-môn Govinda qua đời.",
  "dn19:29.7": "Khi Bà-la-môn Govinda qua đời, vua Disampati than khóc:",
  "dn19:29.8": "‘Than ôi, đúng vào lúc chúng ta giao phó chu toàn mọi công việc cho Bà-la-môn Govinda, rồi sống đầy đủ, hưởng thụ năm dục công đức, thì Bà-la-môn Govinda lại qua đời.’",
  "dn19:29.9": "Khi được nói vậy, này chư vị, hoàng tử Reṇu thưa với vua Disampati rằng:",
  "dn19:29.10": "‘Tâu Đại vương, chớ than khóc quá mức vì Bà-la-môn Govinda đã qua đời.",
  "dn19:29.11": "Tâu Đại vương, Bà-la-môn Govinda có một người con trai thanh niên tên là Jotipāla, còn thông tuệ hơn cha, còn có khả năng thấy rõ lợi ích hơn cha;",
  "dn19:29.12": "những điều mà cha của người ấy từng chỉ dạy về lợi ích, thì thanh niên Jotipāla cũng có thể chỉ dạy được.’",
  "dn19:29.13": "‘Thật vậy sao, này hoàng tử?’",
  "dn19:29.14": "‘Thật vậy, tâu Đại vương.’",
  "dn19:30.0": "6. Chuyện Mahāgovinda",
  "dn19:30.1": "Rồi, này chư vị, vua Disampati gọi một người đến và bảo:",
  "dn19:30.2": "‘Này người kia, hãy đi đến chỗ thanh niên Jotipāla; đến rồi hãy nói với thanh niên Jotipāla như sau:",
  "dn19:30.3": "“Cầu mong điều lành đến với ngài Jotipāla. Vua Disampati cho gọi ngài Jotipāla, vua Disampati muốn gặp ngài Jotipāla.”’",
  "dn19:30.4": "‘Vâng, tâu Đại vương,’ này chư vị, người ấy vâng lời vua Disampati rồi đi đến chỗ thanh niên Jotipāla; đến rồi nói với thanh niên Jotipāla rằng:",
  "dn19:30.5": "‘Cầu mong điều lành đến với ngài Jotipāla. Vua Disampati cho gọi ngài Jotipāla, vua Disampati muốn gặp ngài Jotipāla.’",
  "dn19:30.6": "‘Vâng, này ông,’ này chư vị, thanh niên Jotipāla đáp lời người ấy rồi đi đến chỗ vua Disampati; đến rồi cùng vua Disampati chào hỏi thân tình;",
  "dn19:30.7": "sau khi nói những lời thân hữu, đáng ghi nhớ, liền ngồi xuống một bên. Khi thanh niên Jotipāla ngồi xuống một bên, vua Disampati nói với người ấy rằng:",
  "dn19:30.8": "‘Xin ngài Jotipāla chỉ dạy cho chúng tôi, xin ngài Jotipāla đừng từ chối việc chỉ dạy chúng tôi.",
  "dn19:30.9": "Ta sẽ đặt ngài vào địa vị của cha ngài, sẽ làm lễ tấn phong ngài vào chức Govinda.’",
  "dn19:30.10": "‘Vâng, này ngài,’ này chư vị, thanh niên Jotipāla đã nhận lời vua Disampati.",
  "dn19:31.1": "Rồi, này chư vị, vua Disampati làm lễ tấn phong thanh niên Jotipāla vào chức Govinda, đặt người ấy vào địa vị của cha mình.",
  "dn19:31.2": "Sau khi được tấn phong vào chức Govinda và được đặt vào địa vị của cha mình, thanh niên Jotipāla chỉ dạy những điều lợi ích mà cha mình từng chỉ dạy, và cũng chỉ dạy cả những điều lợi ích mà cha mình chưa từng chỉ dạy;",
  "dn19:31.3": "người ấy đảm đương những công việc mà cha mình từng đảm đương, và cũng đảm đương cả những công việc mà cha mình chưa từng đảm đương.",
  "dn19:31.4": "Bấy giờ người ta nói về người ấy như sau:",
  "dn19:31.5": "“Này các vị, Govinda thật vậy, này các vị, vị Bà-la-môn Mahāgovinda thật vậy.”",
  "dn19:31.6": "Chính theo cách ấy, này các vị, thanh niên Jotipāla Govinda đã có danh xưng là Mahāgovinda.",
  "dn19:32.0": "6.1. Phân chia vương quốc",
  "dn19:32.1": "Rồi này các vị, Bà-la-môn Mahāgovinda đi đến chỗ sáu vị Sát-đế-lỵ ấy; đến nơi, ông nói với sáu vị Sát-đế-lỵ ấy rằng:",
  "dn19:32.2": "“Này các vị, vua Disampati nay đã già nua, lớn tuổi, cao niên, đã đi hết nửa đời và tuổi tác đã chồng chất; này các vị, ai mà biết được mạng sống chứ?",
  "dn19:32.3": "Điều này có thể xảy ra, là khi vua Disampati băng hà, những người làm lễ tấn phong vua sẽ quán đảnh hoàng tử Reṇu lên ngôi vua.",
  "dn19:32.4": "Xin các vị hãy đến chỗ hoàng tử Reṇu; đến nơi, hãy nói với hoàng tử Reṇu như sau:",
  "dn19:32.5": "‘Chúng tôi là những người bạn của ngài Reṇu, thân yêu, khả ái, không trái ý; ngài vui thế nào, chúng tôi vui thế ấy; ngài khổ thế nào, chúng tôi khổ thế ấy.",
  "dn19:32.6": "Này các vị, vua Disampati nay đã già nua, lớn tuổi, cao niên, đã đi hết nửa đời và tuổi tác đã chồng chất; này các vị, ai mà biết được mạng sống chứ?",
  "dn19:32.7": "Điều này có thể xảy ra, là khi vua Disampati băng hà, những người làm lễ tấn phong vua sẽ quán đảnh ngài Reṇu lên ngôi vua.",
  "dn19:32.8": "Nếu ngài Reṇu được vương quyền, xin hãy chia phần vương quốc cho chúng tôi.’”",
  "dn19:33.1": "“Vâng, thưa ngài,” này các vị, sáu vị Sát-đế-lỵ ấy vâng lời Bà-la-môn Mahāgovinda, rồi đi đến chỗ hoàng tử Reṇu; đến nơi, họ nói với hoàng tử Reṇu rằng:",
  "dn19:33.2": "“Chúng tôi là những người bạn của ngài Reṇu, thân yêu, khả ái, không trái ý;",
  "dn19:33.3": "ngài vui thế nào, chúng tôi vui thế ấy; ngài khổ thế nào, chúng tôi khổ thế ấy.",
  "dn19:33.4": "Này các vị, vua Disampati nay đã già nua, lớn tuổi, cao niên, đã đi hết nửa đời và tuổi tác đã chồng chất; này các vị, ai mà biết được mạng sống chứ?",
  "dn19:33.5": "Điều này có thể xảy ra, là khi vua Disampati băng hà, những người làm lễ tấn phong vua sẽ quán đảnh ngài Reṇu lên ngôi vua.",
  "dn19:33.6": "Nếu ngài Reṇu được vương quyền, xin hãy chia phần vương quốc cho chúng tôi.”",
  "dn19:33.7": "“Này các vị, trong lãnh thổ của ta, còn ai khác có thể được an vui ngoài các vị chứ?",
  "dn19:33.8": "Nếu ta được vương quyền, ta sẽ chia phần vương quốc cho các vị.”",
  "dn19:34.1": "Rồi này các vị, sau một thời gian ngày đêm trôi qua, vua Disampati băng hà.",
  "dn19:34.2": "Khi vua Disampati băng hà, những người làm lễ tấn phong vua đã quán đảnh hoàng tử Reṇu lên ngôi vua.",
  "dn19:34.3": "Được quán đảnh vương quyền, vua Reṇu đầy đủ và thọ hưởng năm dục công đức.",
  "dn19:34.4": "Rồi này các vị, Bà-la-môn Mahāgovinda đi đến chỗ sáu vị Sát-đế-lỵ ấy; đến nơi, ông nói với sáu vị Sát-đế-lỵ ấy rằng:",
  "dn19:34.5": "“Này các vị, vua Disampati đã băng hà.",
  "dn19:34.6": "Vua Reṇu đã được quán đảnh vương quyền, đầy đủ và thọ hưởng năm dục công đức.",
  "dn19:34.7": "Này các vị, ai mà biết được các dục là mê say?",
  "dn19:34.8": "Xin các vị hãy đến chỗ vua Reṇu; đến nơi, hãy nói với vua Reṇu như sau:",
  "dn19:34.9": "‘Này các vị, vua Disampati đã băng hà, ngài Reṇu đã được quán đảnh vương quyền, ngài còn nhớ lời nói ấy chăng?’”",
  "dn19:34.10": "“Vâng, thưa ngài,” này các vị, sáu vị Sát-đế-lỵ ấy vâng lời Bà-la-môn Mahāgovinda, rồi đi đến chỗ vua Reṇu; đến nơi, họ nói với vua Reṇu rằng:",
  "dn19:34.11": "“Này các vị, vua Disampati đã băng hà, ngài Reṇu đã được quán đảnh vương quyền, ngài còn nhớ lời nói ấy chăng?”",
  "dn19:34.12": "“Ta nhớ lời nói ấy.",
  "dn19:34.13": "Nhưng này các vị, ai có thể chia đại địa này, kéo dài về phương bắc, hẹp về phương nam như miệng xe, thành bảy phần bằng nhau, phân chia khéo léo?",
  "dn19:34.14": "“Này các vị, ai khác có thể làm được điều ấy ngoài Bà-la-môn Mahāgovinda?”",
  "dn19:35.1": "Rồi này các vị, vua Reṇu gọi một người kia đến:",
  "dn19:35.2": "“Này người kia, hãy đi đến chỗ Bà-la-môn Mahāgovinda; đến nơi, hãy nói với Bà-la-môn Mahāgovinda như sau:",
  "dn19:35.3": "‘Tâu ngài, vua Reṇu cho gọi ngài.’”",
  "dn19:35.4": "“Vâng, thưa đại vương,” này các vị, người ấy vâng lời vua Reṇu, rồi đi đến chỗ Bà-la-môn Mahāgovinda; đến nơi, nói với Bà-la-môn Mahāgovinda rằng:",
  "dn19:35.5": "“Tâu ngài, vua Reṇu cho gọi ngài.”",
  "dn19:35.6": "“Vâng, này anh,” này các vị, Bà-la-môn Mahāgovinda vâng lời người ấy, rồi đi đến chỗ vua Reṇu; đến nơi, ông cùng vua Reṇu chào hỏi thân tình.",
  "dn19:35.7": "Sau khi nói những lời chào hỏi thân thiện, đáng ghi nhớ, ông ngồi xuống một bên. Khi Bà-la-môn Mahāgovinda ngồi xuống một bên, vua Reṇu nói với ông rằng:",
  "dn19:35.8": "“Xin ngài Govinda hãy chia đại địa này, kéo dài về phương bắc, hẹp về phương nam như miệng xe, thành bảy phần bằng nhau, phân chia khéo léo.”",
  "dn19:35.9": "“Vâng, thưa ngài,” này các vị, Bà-la-môn Mahāgovinda vâng lời vua Reṇu, rồi chia đại địa này, kéo dài về phương bắc, hẹp về phương nam như miệng xe, thành bảy phần bằng nhau, phân chia khéo léo.",
  "dn19:36.1": "Ông thiết lập tất cả các vùng như miệng xe.",
  "dn19:36.2": "Trong đó, ở giữa là lãnh thổ của vua Reṇu.",
  "dn19:36.3": "Dantapura của xứ Kaliṅga,",
  "dn19:36.4": "và Potana của xứ Assaka;",
  "dn19:36.5": "Mahesaya của xứ Avantī,",
  "dn19:36.6": "và Roruka của xứ Sovīra.",
  "dn19:36.7": "Mithilā của xứ Videha,",
  "dn19:36.8": "và Campā được dựng ở xứ Aṅga;",
  "dn19:36.9": "và Bārāṇasī của xứ Kāsi,",
  "dn19:36.10": "đó là những nơi do Govinda hoạch định.",
  "dn19:36.11": "Rồi này các vị, sáu vị Sát-đế-lỵ ấy hoan hỷ với phần được chia của mình, toại nguyện ý muốn:",
  "dn19:36.12": "“Điều mà chúng ta mong muốn, điều mà chúng ta ước ao, điều mà chúng ta nhắm đến, điều mà chúng ta cầu đạt, nay chúng ta đã được.”",
  "dn19:36.13": "Sattabhū và Brahmadatta,",
  "dn19:36.14": "Vessabhū cùng với Bharata;",
  "dn19:36.15": "Reṇu và hai Dhataraṭṭha,",
  "dn19:36.16": "khi ấy là bảy vị gánh vác đất nước.",
  "dn19:36.17": "Phần tụng đọc thứ nhất chấm dứt.",
  "dn19:37.0": "6.2. Tiếng tăm vang dậy",
  "dn19:37.1": "Rồi này các vị, sáu vị Sát-đế-lỵ ấy đi đến chỗ Bà-la-môn Mahāgovinda; đến nơi, họ nói với Bà-la-môn Mahāgovinda rằng:",
  "dn19:37.2": "“Như ngài Govinda là người bạn, thân yêu, khả ái, không trái ý của vua Reṇu,",
  "dn19:37.3": "cũng vậy, ngài Govinda cũng là người bạn, thân yêu, khả ái, không trái ý của chúng tôi; xin ngài Govinda hãy chỉ dạy chúng tôi;",
  "dn19:37.4": "xin ngài Govinda đừng từ chối việc chỉ dạy chúng tôi.”",
  "dn19:37.5": "“Vâng, này các vị,” Bà-la-môn Mahāgovinda nhận lời với sáu vị Sát-đế-lỵ ấy.",
  "dn19:37.6": "Rồi này các vị, Bà-la-môn Mahāgovinda chỉ dạy bảy vị vua Sát-đế-lỵ đã được quán đảnh, và dạy thần chú cho bảy vị Bà-la-môn đại phú cùng bảy trăm học trò đã tắm lễ tốt nghiệp.",
  "dn19:38.1": "Rồi này các vị, sau một thời gian, tiếng tăm tốt đẹp này đã nổi lên về Bà-la-môn Mahāgovinda:",
  "dn19:38.2": "“Bà-la-môn Mahāgovinda thật sự thấy Phạm thiên, thật sự đàm đạo, trò chuyện, bàn luận với Phạm thiên.”",
  "dn19:38.3": "Rồi này các vị, Bà-la-môn Mahāgovinda nghĩ rằng:",
  "dn19:38.4": "“Tiếng tăm tốt đẹp này đã nổi lên về ta:",
  "dn19:38.5": "‘Bà-la-môn Mahāgovinda thật sự thấy Phạm thiên, thật sự đàm đạo, trò chuyện, bàn luận với Phạm thiên.’",
  "dn19:38.6": "Nhưng ta không thấy Phạm thiên, không đàm đạo với Phạm thiên, không trò chuyện với Phạm thiên, không bàn luận với Phạm thiên.",
  "dn19:38.7": "Tuy nhiên, ta đã nghe các vị Bà-la-môn già cả, cao niên, các bậc thầy của thầy nói rằng:",
  "dn19:38.8": "‘Ai ẩn cư bốn tháng mùa mưa, tu tập thiền từ bi, người ấy thấy Phạm thiên, đàm đạo với Phạm thiên, trò chuyện với Phạm thiên, bàn luận với Phạm thiên.’",
  "dn19:38.9": "Hay là ta nên ẩn cư bốn tháng mùa mưa, tu tập thiền từ bi.”",
  "dn19:39.1": "Rồi này các vị, Bà-la-môn Mahāgovinda đi đến chỗ vua Reṇu; đến nơi, ông nói với vua Reṇu rằng:",
  "dn19:39.2": "“Tiếng tăm tốt đẹp này đã nổi lên về tôi:",
  "dn19:39.3": "‘Bà-la-môn Mahāgovinda thật sự thấy Phạm thiên, thật sự đàm đạo, trò chuyện, bàn luận với Phạm thiên.’",
  "dn19:39.4": "Nhưng này các vị, tôi không thấy Phạm thiên, không đàm đạo với Phạm thiên, không trò chuyện với Phạm thiên, không bàn luận với Phạm thiên.",
  "dn19:39.5": "Tuy nhiên, tôi đã nghe các vị Bà-la-môn già cả, cao niên, các bậc thầy của thầy nói rằng:",
  "dn19:39.6": "‘Ai ẩn cư bốn tháng mùa mưa, tu tập thiền từ bi, người ấy thấy Phạm thiên, đàm đạo với Phạm thiên, trò chuyện với Phạm thiên, bàn luận với Phạm thiên.’",
  "dn19:39.7": "Tôi muốn ẩn cư bốn tháng mùa mưa, tu tập thiền từ bi;",
  "dn19:39.8": "xin đừng ai đến gặp tôi, ngoại trừ một người mang thức ăn đến.”",
  "dn19:39.9": "“Khi nào ngài Govinda thấy là đúng lúc thì cứ làm.”",
  "dn19:40.1": "Rồi này các vị, Bà-la-môn Mahāgovinda đi đến chỗ sáu vị Sát-đế-lỵ ấy; đến nơi, ông nói với sáu vị Sát-đế-lỵ ấy rằng:",
  "dn19:40.2": "“Tiếng tăm tốt đẹp này đã nổi lên về tôi:",
  "dn19:40.3": "‘Bà-la-môn Mahāgovinda thật sự thấy Phạm thiên, thật sự đàm đạo, trò chuyện, bàn luận với Phạm thiên.’",
  "dn19:40.4": "Nhưng này các vị, tôi không thấy Phạm thiên, không đàm đạo với Phạm thiên, không trò chuyện với Phạm thiên, không bàn luận với Phạm thiên.",
  "dn19:40.5": "Tuy nhiên, tôi đã nghe các vị Bà-la-môn già cả, cao niên, các bậc thầy của thầy nói rằng,",
  "dn19:40.6": "‘Ai ẩn cư bốn tháng mùa mưa, tu tập thiền từ bi, người ấy thấy Phạm thiên, đàm đạo với Phạm thiên, trò chuyện với Phạm thiên, bàn luận với Phạm thiên.’",
  "dn19:40.7": "Tôi muốn ẩn cư bốn tháng mùa mưa, tu tập thiền từ bi;",
  "dn19:40.8": "xin đừng ai đến gặp tôi, ngoại trừ một người mang thức ăn đến.”",
  "dn19:40.9": "“Khi nào ngài Govinda thấy là đúng lúc thì cứ làm.”",
  "dn19:41.1": "Rồi này các vị, Bà-la-môn Mahāgovinda đi đến chỗ bảy vị Bà-la-môn đại phú và bảy trăm học trò đã tắm lễ tốt nghiệp; đến nơi, ông nói với bảy vị Bà-la-môn đại phú và bảy trăm học trò đã tắm lễ tốt nghiệp ấy rằng:",
  "dn19:41.2": "“Tiếng tăm tốt đẹp này đã nổi lên về tôi:",
  "dn19:41.3": "‘Bà-la-môn Mahāgovinda thật sự thấy Phạm thiên, thật sự đàm đạo, trò chuyện, bàn luận với Phạm thiên.’",
  "dn19:41.4": "Nhưng này các vị, tôi không thấy Phạm thiên, không đàm đạo với Phạm thiên, không trò chuyện với Phạm thiên, không bàn luận với Phạm thiên.",
  "dn19:41.5": "Tuy nhiên, tôi đã nghe các vị Bà-la-môn già cả, cao niên, các bậc thầy của thầy nói rằng:",
  "dn19:41.6": "‘Ai ẩn cư bốn tháng mùa mưa, tu tập thiền từ bi, người ấy thấy Phạm thiên, đàm đạo với Phạm thiên, trò chuyện với Phạm thiên, bàn luận với Phạm thiên.’",
  "dn19:41.7": "Vậy thì này các vị, hãy tụng đọc rộng rãi các thần chú theo điều đã nghe, theo điều đã học thuộc, và hãy dạy thần chú cho nhau;",
  "dn19:41.8": "Này ngài, tôi muốn sống viễn ly bốn tháng mùa mưa, tu tập thiền tâm bi; ",
  "dn19:41.9": "không ai được đến gặp tôi, ngoại trừ một người mang cơm đến.” ",
  "dn19:41.10": "“Khi nào tôn giả Govinda thấy là đúng lúc thì cứ làm.” ",
  "dn19:42.1": "Rồi này ngài, bà-la-môn Mahāgovinda đi đến chỗ bốn mươi người vợ đồng hàng; đến nơi, ông nói với bốn mươi người vợ đồng hàng ấy rằng: ",
  "dn19:42.2": "“Thưa các bà, tiếng tốt đẹp này đã được truyền rộng về tôi: ",
  "dn19:42.3": "‘Bà-la-môn Mahāgovinda tận mắt thấy Phạm thiên, bà-la-môn Mahāgovinda tận mắt đàm đạo, trò chuyện, bàn luận với Phạm thiên.’ ",
  "dn19:42.4": "Nhưng thưa các bà, tôi không thấy Phạm thiên, không đàm đạo với Phạm thiên, không trò chuyện với Phạm thiên, không bàn luận với Phạm thiên. ",
  "dn19:42.5": "Tuy nhiên, tôi có nghe các vị bà-la-môn già cả, lớn tuổi, các bậc thầy và thầy của thầy nói rằng ",
  "dn19:42.6": "‘Ai sống viễn ly bốn tháng mùa mưa, tu tập thiền tâm bi, người ấy sẽ thấy Phạm thiên, sẽ đàm đạo với Phạm thiên, sẽ trò chuyện với Phạm thiên, sẽ bàn luận với Phạm thiên.’ ",
  "dn19:42.7": "Thưa các bà, tôi muốn sống viễn ly bốn tháng mùa mưa, tu tập thiền tâm bi; ",
  "dn19:42.8": "không ai được đến gặp tôi, ngoại trừ một người mang cơm đến.” ",
  "dn19:42.9": "“Khi nào tôn giả Govinda thấy là đúng lúc thì cứ làm.” ",
  "dn19:43.1": "Rồi này ngài, bà-la-môn Mahāgovinda cho xây một hội trường mới ở phía đông thành phố, rồi sống viễn ly bốn tháng mùa mưa, tu tập thiền tâm bi; ",
  "dn19:43.2": "quả thật không ai đến gặp ông, ngoại trừ một người mang cơm đến. ",
  "dn19:43.3": "Rồi này ngài, sau khi bốn tháng trôi qua, bà-la-môn Mahāgovinda sinh ra chán nản, sinh ra bồn chồn: ",
  "dn19:43.4": "“Tôi có nghe các vị bà-la-môn già cả, lớn tuổi, các bậc thầy và thầy của thầy nói rằng: ",
  "dn19:43.5": "‘Ai sống viễn ly bốn tháng mùa mưa, tu tập thiền tâm bi, người ấy sẽ thấy Phạm thiên, sẽ đàm đạo với Phạm thiên, sẽ trò chuyện với Phạm thiên, sẽ bàn luận với Phạm thiên.’ ",
  "dn19:43.6": "Nhưng tôi không thấy Phạm thiên, không đàm đạo với Phạm thiên, không trò chuyện với Phạm thiên, không bàn luận với Phạm thiên.” ",
  "dn19:44.0": "6.3. Đàm đạo với Phạm thiên ",
  "dn19:44.1": "Rồi này ngài, Phạm thiên Sanaṅkumāra biết được ý nghĩ trong tâm của bà-la-môn Mahāgovinda—ví như một người lực lưỡng co cánh tay đang duỗi ra, hoặc duỗi cánh tay đang co lại; cũng vậy—biến mất khỏi cõi Phạm thiên và hiện ra trước mặt bà-la-môn Mahāgovinda. ",
  "dn19:44.2": "Rồi này ngài, bà-la-môn Mahāgovinda liền sinh sợ hãi, kinh hoàng, rợn tóc gáy khi thấy một hình sắc chưa từng thấy trước đây. ",
  "dn19:44.3": "Rồi này ngài, bà-la-môn Mahāgovinda, sợ hãi, xúc động, lông tóc dựng ngược, nói với Phạm thiên Sanaṅkumāra bằng kệ rằng: ",
  "dn19:44.4": "“Dung sắc đẹp, danh vọng lớn, đầy uy quang, ",
  "dn19:44.5": "ngài là ai vậy, thưa tôn giả? ",
  "dn19:44.6": "Chúng tôi không biết nên hỏi ngài, ",
  "dn19:44.7": "làm sao chúng tôi biết được ngài?” ",
  "dn19:44.8": "“Họ biết ta là Kumāra, ",
  "dn19:44.9": "vị thường hằng trong cõi Phạm thiên; ",
  "dn19:44.10": "chư thiên đều biết ta, ",
  "dn19:44.11": "Govinda, hãy biết như vậy.” ",
  "dn19:44.12": "“Chỗ ngồi, nước, nước rửa chân, ",
  "dn19:44.13": "và rau mật xin dâng lên Phạm thiên; ",
  "dn19:44.14": "chúng tôi xin hỏi ngài về lễ kính, ",
  "dn19:44.15": "xin ngài nhận lễ kính của chúng tôi.” ",
  "dn19:44.16": "“Ta nhận lễ kính của ngươi, ",
  "dn19:44.17": "điều mà ngươi nói đó, Govinda; ",
  "dn19:44.18": "vì lợi ích trong hiện tại, ",
  "dn19:44.19": "và vì an lạc đời sau; ",
  "dn19:44.20": "ngươi đã được cho phép, hãy hỏi ",
  "dn19:44.21": "bất cứ điều gì ngươi mong muốn.” ",
  "dn19:45.1": "Rồi này ngài, bà-la-môn Mahāgovinda nghĩ rằng: ",
  "dn19:45.2": "“Ta đã được Phạm thiên Sanaṅkumāra cho phép. ",
  "dn19:45.3": "Vậy ta nên hỏi Phạm thiên Sanaṅkumāra về lợi ích hiện tại hay lợi ích đời sau?” ",
  "dn19:45.4": "Rồi này ngài, bà-la-môn Mahāgovinda nghĩ rằng: ",
  "dn19:45.5": "“Ta khéo léo về những lợi ích hiện tại, người khác cũng hỏi ta về lợi ích hiện tại. ",
  "dn19:45.6": "Vậy ta nên chỉ hỏi Phạm thiên Sanaṅkumāra về lợi ích đời sau.” ",
  "dn19:45.7": "Rồi này ngài, bà-la-môn Mahāgovinda nói với Phạm thiên Sanaṅkumāra bằng kệ rằng: ",
  "dn19:45.8": "“Tôi hỏi Phạm thiên Sanaṅkumāra, ",
  "dn19:45.9": "người còn nghi, hỏi bậc không nghi về các tri kiến cao hơn; ",
  "dn19:45.10": "đứng ở đâu, tu học điều gì, ",
  "dn19:45.11": "người phàm mới đạt đến cõi Phạm thiên bất tử?” ",
  "dn19:45.12": "“Từ bỏ chấp ngã đối với loài người, này Bà-la-môn, ",
  "dn19:45.13": "nhất tâm, hướng trọn về tâm bi; ",
  "dn19:45.14": "không còn mùi nhơ, từ bỏ dâm dục; ",
  "dn19:45.15": "đứng vững ở đây, tu học ở đây; ",
  "dn19:45.16": "người phàm đạt đến cõi Phạm thiên bất tử.” ",
  "dn19:46.1": "“‘Từ bỏ chấp ngã’, thưa ngài, điều ấy tôi hiểu. ",
  "dn19:46.2": "Ở đây có người từ bỏ ít hay nhiều tài sản, từ bỏ ít hay nhiều bà con thân thuộc, cạo bỏ tóc râu, khoác y ca-sa, từ gia đình đi xuất gia không gia đình, ",
  "dn19:46.3": "như vậy, thưa ngài, tôi hiểu là ‘từ bỏ chấp ngã’. ",
  "dn19:46.4": "‘Nhất tâm’, thưa ngài, điều ấy tôi hiểu. ",
  "dn19:46.5": "Ở đây có người ưa thích chỗ ở thanh vắng: rừng, gốc cây, núi, hang núi, động đá, nghĩa địa, rừng hoang, chỗ trống, đống rơm, ",
  "dn19:46.6": "như vậy, thưa ngài, tôi hiểu là ‘nhất tâm’. ",
  "dn19:46.7": "‘Hướng trọn về tâm bi’, thưa ngài, điều ấy tôi hiểu. ",
  "dn19:46.8": "Ở đây có người an trú, biến mãn một phương với tâm câu hữu với bi; cũng vậy phương thứ hai, cũng vậy phương thứ ba, cũng vậy phương thứ tư. Như vậy, trên, dưới, ngang, khắp mọi nơi, đối với tất cả như với chính mình, vị ấy an trú biến mãn toàn thế giới với tâm câu hữu với bi, rộng lớn, cao thượng, vô lượng, không oán, không hại. ",
  "dn19:46.9": "Như vậy, thưa ngài, tôi hiểu là ‘hướng trọn về tâm bi’. ",
  "dn19:46.10": "Nhưng còn khi ngài nói về ‘mùi nhơ’, thưa ngài, tôi không hiểu. ",
  "dn19:46.11": "Những gì là mùi nhơ nơi loài người, thưa Phạm thiên? ",
  "dn19:46.12": "Xin bậc hiền trí hãy nói rõ điều ấy ở đây cho người không biết; ",
  "dn19:46.13": "do bị che lấp bởi điều gì mà chúng sinh bị gió cuốn đi, ",
  "dn19:46.14": "rơi vào đọa xứ, bị ngăn che khỏi cõi Phạm thiên?” ",
  "dn19:46.15": "“Phẫn nộ, nói dối, lừa đảo và phản bội, ",
  "dn19:46.16": "keo kiệt, ngã mạn, ganh tị; ",
  "dn19:46.17": "tham muốn, nghi hoặc, làm hại người khác, ",
  "dn19:46.18": "tham lam, sân hận, say đắm và si mê; ",
  "dn19:46.19": "ai bị trói buộc vào những điều ấy thì không lìa mùi nhơ, ",
  "dn19:46.20": "rơi vào đọa xứ, bị ngăn che khỏi cõi Phạm thiên.” ",
  "dn19:46.21": "“Thưa ngài, nay tôi đã hiểu khi ngài nói về mùi nhơ. Những điều ấy không dễ dập tắt khi còn sống đời tại gia. ",
  "dn19:46.22": "Thưa ngài, tôi sẽ xuất gia, từ gia đình đi vào đời không gia đình.” ",
  "dn19:46.23": "“Khi nào tôn giả Govinda thấy là đúng lúc thì cứ làm.” ",
  "dn19:47.0": "6.4. Từ biệt vua Reṇu ",
  "dn19:47.1": "Rồi này ngài, bà-la-môn Mahāgovinda đi đến chỗ vua Reṇu; đến nơi, ông nói với vua Reṇu rằng: ",
  "dn19:47.2": "“Nay bệ hạ hãy tìm một vị tế sư khác, người sẽ hướng dẫn vương quốc của bệ hạ. ",
  "dn19:47.3": "Thưa ngài, tôi muốn xuất gia, từ gia đình đi vào đời không gia đình. ",
  "dn19:47.4": "Vì như tôi đã nghe từ Phạm thiên khi ngài nói về mùi nhơ, những điều ấy không dễ dập tắt khi còn sống đời tại gia. ",
  "dn19:47.5": "Thưa ngài, tôi sẽ xuất gia, từ gia đình đi vào đời không gia đình.” ",
  "dn19:47.6": "“Tôi xin từ biệt đức vua, ",
  "dn19:47.7": "vua Reṇu, bậc chủ đất này; ",
  "dn19:47.8": "xin ngài tự lo việc nước, ",
  "dn19:47.9": "tôi không còn vui với chức tế sư.” ",
  "dn19:47.10": "“Nếu ông còn thiếu dục lạc gì, ",
  "dn19:47.11": "ta sẽ làm cho ông đầy đủ; ",
  "dn19:47.12": "ai hại ông, ta sẽ ngăn lại, ",
  "dn19:47.13": "vì ta là chủ tướng của đất nước; ",
  "dn19:47.14": "ông là cha, ta là con, ",
  "dn19:47.15": "Govinda, xin đừng bỏ chúng ta.” ",
  "dn19:47.16": "“Tôi không thiếu dục lạc gì, ",
  "dn19:47.17": "cũng không có ai hại tôi; ",
  "dn19:47.18": "nghe được lời của bậc phi nhân, ",
  "dn19:47.19": "nên tôi không còn vui với đời sống tại gia.” ",
  "dn19:47.20": "“Bậc phi nhân ấy có hình dạng thế nào, ",
  "dn19:47.21": "Ngài đã nói với ông điều gì,",
  "dn19:47.22": "mà sau khi nghe xong ông lại từ bỏ chúng tôi,",
  "dn19:47.23": "từ bỏ nhà cửa và tất cả chúng tôi?”",
  "dn19:47.24": "“Trước đây, khi tôi đang ở ẩn,",
  "dn19:47.25": "và đang có ý muốn cúng tế;",
  "dn19:47.26": "một ngọn lửa đã được đốt lên,",
  "dn19:47.27": "được trải quanh bằng lá cỏ kusa.",
  "dn19:47.28": "Rồi một vị Phạm thiên hiện ra trước tôi,",
  "dn19:47.29": "từ cõi Phạm thiên, bậc thường hằng;",
  "dn19:47.30": "vị ấy đã giải đáp câu hỏi cho tôi,",
  "dn19:47.31": "nghe xong điều ấy, tôi không còn vui thích đời sống tại gia.”",
  "dn19:47.32": "“Tôi tin lời ngài,",
  "dn19:47.33": "điều mà ngài Govinda nói;",
  "dn19:47.34": "sau khi nghe lời của bậc phi nhân,",
  "dn19:47.35": "làm sao có thể hành xử khác đi được.",
  "dn19:47.36": "Chúng tôi sẽ đi theo ngài,",
  "dn19:47.37": "xin ngài Govinda làm bậc đạo sư của chúng tôi;",
  "dn19:47.38": "như viên ngọc lưu ly,",
  "dn19:47.39": "không tì vết, trong sạch, đẹp đẽ;",
  "dn19:47.40": "cũng vậy, chúng tôi sẽ sống thanh tịnh,",
  "dn19:47.41": "theo lời chỉ dạy của ngài Govinda.",
  "dn19:47.42": "Nếu ngài Govinda xuất gia từ bỏ gia đình, sống không gia đình, thì chúng tôi cũng sẽ xuất gia từ bỏ gia đình, sống không gia đình.",
  "dn19:47.43": "Con đường nào là con đường của ngài, con đường ấy sẽ là con đường của chúng tôi.”",
  "dn19:48.0": "6.5. Mời sáu vị Sát-đế-lỵ",
  "dn19:48.1": "Rồi này các ông, bà-la-môn Mahāgovinda đi đến chỗ sáu vị Sát-đế-lỵ ấy; đến nơi, ông nói với sáu vị Sát-đế-lỵ ấy như sau:",
  "dn19:48.2": "“Giờ đây chư vị hãy tìm một vị tế sư khác, người sẽ chỉ dạy chư vị trong việc trị nước.",
  "dn19:48.3": "Thưa chư vị, tôi muốn xuất gia từ bỏ gia đình, sống không gia đình.",
  "dn19:48.4": "Vì như tôi đã được nghe khi Phạm thiên nói về ô uế, những ai sống tại gia không thể dễ dàng được thanh tịnh.",
  "dn19:48.5": "Thưa chư vị, tôi sẽ xuất gia từ bỏ gia đình, sống không gia đình.”",
  "dn19:49.1": "Rồi này các ông, sáu vị Sát-đế-lỵ ấy lui sang một bên và suy nghĩ như sau:",
  "dn19:49.2": "“Những bà-la-môn này vốn tham của cải;",
  "dn19:49.3": "hay là chúng ta dùng của cải để thuyết phục bà-la-môn Mahāgovinda.”",
  "dn19:49.4": "Họ đến gặp bà-la-môn Mahāgovinda và nói như sau:",
  "dn19:49.5": "“Thưa ngài, trong bảy vương quốc này có rất nhiều tài sản, ngài cần bao nhiêu thì cứ mang đến bấy nhiêu.”",
  "dn19:49.6": "“Thưa chư vị, riêng tôi cũng đã có nhiều tài sản, nhờ chính chư vị mà có.",
  "dn19:49.7": "Tất cả những thứ ấy tôi sẽ từ bỏ để xuất gia từ bỏ gia đình, sống không gia đình.",
  "dn19:49.8": "Vì như tôi đã được nghe khi Phạm thiên nói về ô uế, những ai sống tại gia không thể dễ dàng được thanh tịnh,",
  "dn19:49.9": "thưa chư vị, tôi sẽ xuất gia từ bỏ gia đình, sống không gia đình.”",
  "dn19:49.10": "Rồi này các ông, sáu vị Sát-đế-lỵ ấy lui sang một bên và suy nghĩ như sau:",
  "dn19:49.11": "“Những bà-la-môn này vốn tham phụ nữ;",
  "dn19:49.12": "hay là chúng ta dùng phụ nữ để thuyết phục bà-la-môn Mahāgovinda.”",
  "dn19:49.13": "Họ đến gặp bà-la-môn Mahāgovinda và nói như sau:",
  "dn19:49.14": "“Thưa ngài, trong bảy vương quốc này có rất nhiều phụ nữ, ngài cần bao nhiêu thì cứ đem đến bấy nhiêu.”",
  "dn19:49.15": "“Thưa chư vị, riêng tôi cũng đã có bốn mươi người vợ đồng hàng.",
  "dn19:49.16": "Tất cả họ tôi cũng sẽ từ bỏ để xuất gia từ bỏ gia đình, sống không gia đình.",
  "dn19:49.17": "Vì như tôi đã được nghe khi Phạm thiên nói về ô uế, những ai sống tại gia không thể dễ dàng được thanh tịnh,",
  "dn19:49.18": "thưa chư vị, tôi sẽ xuất gia từ bỏ gia đình, sống không gia đình.”",
  "dn19:50.1": "“Nếu ngài Govinda xuất gia từ bỏ gia đình, sống không gia đình, thì chúng tôi cũng sẽ xuất gia từ bỏ gia đình, sống không gia đình; con đường nào là con đường của ngài, con đường ấy sẽ là con đường của chúng tôi.”",
  "dn19:50.2": "“Nếu các vị từ bỏ các dục,",
  "dn19:50.3": "nơi mà phàm phu bị trói buộc;",
  "dn19:50.4": "hãy tinh tấn khởi hành, hãy kiên cường,",
  "dn19:50.5": "đầy đủ sức mạnh của nhẫn nại và định tĩnh.",
  "dn19:50.6": "Đây là con đường, con đường ngay thẳng,",
  "dn19:50.7": "đây là con đường vô thượng;",
  "dn19:50.8": "chánh pháp được người hiền gìn giữ,",
  "dn19:50.9": "đưa đến tái sinh vào cõi Phạm thiên.”",
  "dn19:51.1": "“Vậy thì xin ngài Govinda hãy chờ bảy năm.",
  "dn19:51.2": "Sau bảy năm, chúng tôi cũng sẽ xuất gia từ bỏ gia đình, sống không gia đình; con đường nào là con đường của ngài, con đường ấy sẽ là con đường của chúng tôi.”",
  "dn19:51.3": "“Thưa chư vị, bảy năm là quá lâu, tôi không thể chờ chư vị bảy năm được.",
  "dn19:51.4": "Vì này chư vị, ai biết được mạng sống sẽ ra sao?",
  "dn19:51.5": "Đời sau phải đi đến, điều cần suy xét phải được hiểu rõ, điều thiện phải được làm, phạm hạnh phải được sống; người đã sinh ra thì không thể không chết.",
  "dn19:51.6": "Vì như tôi đã được nghe khi Phạm thiên nói về ô uế, những ai sống tại gia không thể dễ dàng được thanh tịnh,",
  "dn19:51.7": "thưa chư vị, tôi sẽ xuất gia từ bỏ gia đình, sống không gia đình.”",
  "dn19:52.1": "“Vậy thì xin ngài Govinda hãy chờ sáu năm …",
  "dn19:52.2": "hãy chờ năm năm …",
  "dn19:52.3": "hãy chờ bốn năm …",
  "dn19:52.4": "hãy chờ ba năm …",
  "dn19:52.5": "hãy chờ hai năm …",
  "dn19:52.6": "hãy chờ một năm, sau một năm chúng tôi cũng sẽ xuất gia từ bỏ gia đình, sống không gia đình; con đường nào là con đường của ngài, con đường ấy sẽ là con đường của chúng tôi.”",
  "dn19:53.1": "“Thưa chư vị, một năm là quá lâu, tôi không thể chờ chư vị một năm được.",
  "dn19:53.2": "Vì này chư vị, ai biết được mạng sống sẽ ra sao?",
  "dn19:53.3": "Đời sau phải đi đến, điều cần suy xét phải được hiểu rõ, điều thiện phải được làm, phạm hạnh phải được sống; người đã sinh ra thì không thể không chết.",
  "dn19:53.4": "Vì như tôi đã được nghe khi Phạm thiên nói về ô uế, những ai sống tại gia không thể dễ dàng được thanh tịnh,",
  "dn19:53.5": "thưa chư vị, tôi sẽ xuất gia từ bỏ gia đình, sống không gia đình.”",
  "dn19:53.6": "“Vậy thì xin ngài Govinda hãy chờ bảy tháng, sau bảy tháng chúng tôi cũng sẽ xuất gia từ bỏ gia đình, sống không gia đình; con đường nào là con đường của ngài, con đường ấy sẽ là con đường của chúng tôi.”",
  "dn19:54.1": "“Thưa chư vị, bảy tháng là quá lâu, tôi không thể chờ chư vị bảy tháng được.",
  "dn19:54.2": "Vì này chư vị, ai biết được mạng sống sẽ ra sao?",
  "dn19:54.3": "Đời sau phải đi đến, điều cần suy xét phải được hiểu rõ, điều thiện phải được làm, phạm hạnh phải được sống; người đã sinh ra thì không thể không chết.",
  "dn19:54.4": "Vì như tôi đã được nghe khi Phạm thiên nói về ô uế, những ai sống tại gia không thể dễ dàng được thanh tịnh,",
  "dn19:54.5": "thưa chư vị, tôi sẽ xuất gia từ bỏ gia đình, sống không gia đình.”",
  "dn19:54.6": "“Vậy thì xin ngài Govinda hãy chờ sáu tháng …",
  "dn19:54.7": "hãy chờ năm tháng …",
  "dn19:54.8": "hãy chờ bốn tháng …",
  "dn19:54.9": "hãy chờ ba tháng …",
  "dn19:54.10": "hãy chờ hai tháng …",
  "dn19:54.11": "hãy chờ một tháng …",
  "dn19:54.12": "hãy chờ nửa tháng, sau nửa tháng chúng tôi cũng sẽ xuất gia từ bỏ gia đình, sống không gia đình; con đường nào là con đường của ngài, con đường ấy sẽ là con đường của chúng tôi.”",
  "dn19:55.1": "“Thưa chư vị, nửa tháng là quá lâu, tôi không thể chờ chư vị nửa tháng được.",
  "dn19:55.2": "Vì này chư vị, ai biết được mạng sống sẽ ra sao?",
  "dn19:55.3": "Đời sau phải đi đến, điều cần suy xét phải được hiểu rõ, điều thiện phải được làm, phạm hạnh phải được sống; người đã sinh ra thì không thể không chết.",
  "dn19:55.4": "Vì như tôi đã được nghe khi Phạm thiên nói về ô uế, những ai sống tại gia không thể dễ dàng được thanh tịnh,",
  "dn19:55.5": "thưa chư vị, tôi sẽ xuất gia từ bỏ gia đình, sống không gia đình.”",
  "dn19:55.6": "“Vậy thì xin ngài Govinda hãy chờ bảy ngày, cho đến khi chúng tôi sắp đặt các con và anh em mình cai trị vương quốc; sau bảy ngày, chúng tôi cũng sẽ xuất gia từ bỏ gia đình, sống không gia đình; con đường nào là con đường của ngài, con đường ấy sẽ là con đường của chúng tôi.”",
  "dn19:55.7": "“Bảy ngày thì không lâu, thưa chư vị, tôi sẽ chờ chư vị bảy ngày.”",
  "dn19:56.0": "6.6. Mời các đại phú bà-la-môn và những người khác",
  "dn19:56.1": "Rồi này các ông, bà-la-môn Mahāgovinda đi đến chỗ bảy vị đại phú bà-la-môn và bảy trăm học trò đã tắm gội; đến nơi, ông nói với bảy vị đại phú bà-la-môn và bảy trăm học trò ấy như sau:",
  "dn19:56.2": "“Giờ đây chư vị hãy tìm một vị thầy khác, người sẽ dạy các thần chú cho chư vị.",
  "dn19:56.3": "Thưa chư vị, tôi muốn xuất gia từ bỏ gia đình, sống không gia đình.",
  "dn19:56.4": "Vì như tôi đã được nghe khi Phạm thiên nói về ô uế. Những ai sống tại gia không thể dễ dàng được thanh tịnh,",
  "dn19:56.5": "thưa chư vị, tôi sẽ xuất gia từ bỏ gia đình, sống không gia đình.”",
  "dn19:56.6": "“Xin ngài Govinda đừng từ bỏ gia đình để xuất gia không gia đình.",
  "dn19:56.7": "Này ngài, đời sống xuất gia thì ít uy thế và ít lợi dưỡng;",
  "dn19:56.8": "còn đời sống Bà-la-môn thì có uy thế lớn và lợi dưỡng lớn.”",
  "dn19:56.9": "“Xin chư vị đừng nói như vậy: ‘Đời sống xuất gia thì ít uy thế và ít lợi dưỡng, còn đời sống Bà-la-môn thì có uy thế lớn và lợi dưỡng lớn.’",
  "dn19:56.10": "Này chư vị, ngoài ta ra, còn ai có uy thế hơn hay lợi dưỡng hơn nữa?",
  "dn19:56.11": "Vì nay ta là vua giữa các vua, là Phạm thiên giữa các Bà-la-môn, là chư thiên giữa các gia chủ.",
  "dn19:56.12": "Tất cả điều ấy, ta sẽ từ bỏ để xuất gia, từ gia đình sang đời không gia đình.",
  "dn19:56.13": "Nhưng như ta đã nghe khi Phạm thiên nói về ô uế, những điều ấy không thể được dập tắt khi còn sống đời tại gia.",
  "dn19:56.14": "Này chư vị, ta sẽ xuất gia, từ gia đình sang đời không gia đình.”",
  "dn19:56.15": "“Nếu ngài Govinda xuất gia, từ gia đình sang đời không gia đình, thì chúng tôi cũng sẽ xuất gia, từ gia đình sang đời không gia đình; con đường nào là con đường của ngài, đó sẽ là con đường của chúng tôi.”",
  "dn19:57.0": "6.7. Báo cho các người vợ",
  "dn19:57.1": "Rồi này chư vị, Bà-la-môn Mahāgovinda đi đến chỗ bốn mươi người vợ đồng hàng của mình; đến nơi, ông nói với bốn mươi người vợ đồng hàng ấy rằng:",
  "dn19:57.2": "“Vị nào trong các bà muốn thì hãy trở về gia tộc thân quyến của mình, hoặc tìm một người chồng khác.",
  "dn19:57.3": "Này các bà, ta muốn xuất gia, từ gia đình sang đời không gia đình.",
  "dn19:57.4": "Nhưng như ta đã nghe khi Phạm thiên nói về ô uế, những điều ấy không thể được dập tắt khi còn sống đời tại gia.",
  "dn19:57.5": "Này các bà, ta sẽ xuất gia, từ gia đình sang đời không gia đình.”",
  "dn19:57.6": "“Chính chàng là thân quyến của chúng thiếp khi chúng thiếp cần thân quyến, chính chàng là chồng của chúng thiếp khi chúng thiếp cần chồng.",
  "dn19:57.7": "Nếu ngài Govinda xuất gia, từ gia đình sang đời không gia đình, thì chúng thiếp cũng sẽ xuất gia, từ gia đình sang đời không gia đình; con đường nào là con đường của ngài, đó sẽ là con đường của chúng thiếp.”",
  "dn19:58.0": "6.8. Mahāgovinda xuất gia",
  "dn19:58.1": "Rồi này chư vị, sau bảy ngày, Bà-la-môn Mahāgovinda cạo bỏ râu tóc, khoác y ca-sa, xuất gia từ gia đình sang đời không gia đình.",
  "dn19:58.2": "Khi Bà-la-môn Mahāgovinda đã xuất gia, thì bảy vị vua thuộc dòng Sát-đế-lỵ đã làm lễ quán đảnh, bảy vị đại phú Bà-la-môn, bảy trăm người học trò, bốn mươi người vợ đồng hàng, cùng nhiều ngàn Sát-đế-lỵ, nhiều ngàn Bà-la-môn, nhiều ngàn gia chủ, và nhiều phụ nữ trong hậu cung, đều cạo bỏ râu tóc, khoác y ca-sa, theo Bà-la-môn Mahāgovinda xuất gia từ gia đình sang đời không gia đình.",
  "dn19:58.3": "Này chư vị, được hội chúng ấy vây quanh, Bà-la-môn Mahāgovinda du hành qua các làng, thị trấn và kinh thành.",
  "dn19:58.4": "Này chư vị, vào thời ấy, bất cứ khi nào Bà-la-môn Mahāgovinda đến một làng hay một thị trấn, thì tại đó ông là vua giữa các vua, là Phạm thiên giữa các Bà-la-môn, là chư thiên giữa các gia chủ.",
  "dn19:58.5": "Vào thời ấy, loài người hoặc ném lên hoặc rảy lên.",
  "dn19:58.6": "Họ nói như sau:",
  "dn19:58.7": "‘Kính lễ Bà-la-môn Mahāgovinda, kính lễ bảy vị tế sư.’”",
  "dn19:59.1": "Này chư vị, Bà-la-môn Mahāgovinda an trú, biến mãn một phương với tâm câu hữu với từ; cũng vậy phương thứ hai, cũng vậy phương thứ ba, cũng vậy phương thứ tư. Như vậy, trên, dưới, ngang, khắp mọi nơi, đối với tất cả như với chính mình, ông an trú biến mãn toàn thế giới với tâm câu hữu với từ, rộng lớn, cao thượng, vô lượng, không oán, không hại.",
  "dn19:59.2": "Với tâm câu hữu với bi …",
  "dn19:59.3": "với tâm câu hữu với hỷ …",
  "dn19:59.4": "với tâm câu hữu với xả … không oán, không hại, ông an trú biến mãn.",
  "dn19:59.5": "Và ông đã thuyết dạy cho các đệ tử con đường đưa đến cộng trú với Phạm thiên giới.",
  "dn19:60.1": "Này chư vị, những đệ tử nào của Bà-la-môn Mahāgovinda thời ấy hiểu biết trọn vẹn toàn bộ giáo pháp,",
  "dn19:60.2": "thì sau khi thân hoại mạng chung, được sinh vào cõi lành, Phạm thiên giới.",
  "dn19:60.3": "Những ai không hiểu biết trọn vẹn toàn bộ giáo pháp, thì sau khi thân hoại mạng chung, một số được sinh vào cộng trú với chư thiên Tha hóa tự tại;",
  "dn19:60.4": "một số được sinh vào cộng trú với chư thiên Hóa lạc;",
  "dn19:60.5": "một số được sinh vào cộng trú với chư thiên Đâu-suất;",
  "dn19:60.6": "một số được sinh vào cộng trú với chư thiên Dạ-ma;",
  "dn19:60.7": "một số được sinh vào cộng trú với chư thiên Tam thập tam;",
  "dn19:60.8": "một số được sinh vào cộng trú với chư thiên Tứ đại vương;",
  "dn19:60.9": "còn những ai thành tựu thân phận thấp nhất thì được sinh vào chúng Càn-thát-bà.",
  "dn19:60.10": "Như vậy, này chư vị, sự xuất gia của tất cả những thiện nam tử ấy đều không uổng phí, không vô ích, có kết quả, có thành tựu.”",
  "dn19:60.11": "“Bạch Thế Tôn, Ngài có nhớ việc ấy không?”",
  "dn19:61.1": "“Ta nhớ, này Pañcasikha.",
  "dn19:61.2": "Vào thời ấy, Ta là Bà-la-môn Mahāgovinda.",
  "dn19:61.3": "Ta đã thuyết dạy cho các đệ tử ấy con đường đưa đến cộng trú với Phạm thiên giới.",
  "dn19:61.4": "Nhưng này Pañcasikha, đời sống phạm hạnh ấy của Ta không đưa đến yếm ly, không đưa đến ly tham, không đưa đến đoạn diệt, không đưa đến an tịnh, không đưa đến thắng trí, không đưa đến giác ngộ, không đưa đến Niết-bàn, mà chỉ đưa đến tái sinh vào Phạm thiên giới.",
  "dn19:61.5": "Còn này Pañcasikha, đời sống phạm hạnh này của Ta đưa đến hoàn toàn yếm ly, ly tham, đoạn diệt, an tịnh, thắng trí, giác ngộ, Niết-bàn.",
  "dn19:61.6": "Và này Pañcasikha, đời sống phạm hạnh nào đưa đến hoàn toàn yếm ly, ly tham, đoạn diệt, an tịnh, thắng trí, giác ngộ, Niết-bàn?",
  "dn19:61.7": "Chính là Thánh đạo tám ngành này.",
  "dn19:61.8": "Tức là: chánh kiến, chánh tư duy, chánh ngữ, chánh nghiệp, chánh mạng, chánh tinh tấn, chánh niệm, chánh định.",
  "dn19:61.9": "Này Pañcasikha, đó là đời sống phạm hạnh đưa đến hoàn toàn yếm ly, ly tham, đoạn diệt, an tịnh, thắng trí, giác ngộ, Niết-bàn.",
  "dn19:62.1": "Này Pañcasikha, những đệ tử nào của Ta hiểu biết trọn vẹn toàn bộ giáo pháp, thì do đoạn tận các lậu hoặc, ngay trong hiện tại, tự mình với thắng trí chứng ngộ và an trú vô lậu tâm giải thoát, tuệ giải thoát;",
  "dn19:62.2": "những ai không hiểu biết trọn vẹn toàn bộ giáo pháp, thì do đoạn tận năm hạ phần kiết sử, trở thành bậc hóa sinh, tại đó nhập Niết-bàn, không còn trở lui thế giới này nữa;",
  "dn19:62.3": "những ai không hiểu biết trọn vẹn toàn bộ giáo pháp, một số do đoạn tận ba kiết sử, và do tham, sân, si được làm cho mỏng nhẹ, trở thành bậc Nhất lai, chỉ còn trở lại thế giới này một lần nữa rồi sẽ chấm dứt khổ đau;",
  "dn19:62.4": "những ai không hiểu biết trọn vẹn toàn bộ giáo pháp, một số do đoạn tận ba kiết sử, trở thành bậc Dự lưu, không còn rơi vào đọa xứ, chắc chắn hướng đến giác ngộ.",
  "dn19:62.5": "Như vậy, này Pañcasikha, sự xuất gia của tất cả những thiện nam tử này đều không uổng phí, không vô ích, có kết quả, có thành tựu.”",
  "dn19:62.6": "Thế Tôn đã nói như vậy.",
  "dn19:62.7": "Pañcasikha, con trai của Càn-thát-bà, hoan hỷ tín thọ lời Thế Tôn dạy, đảnh lễ Thế Tôn, đi nhiễu bên phải rồi biến mất ngay tại chỗ ấy.",
  "dn19:62.8": "Kinh Mahāgovinda, phần thứ sáu, chấm dứt."
}
window.BILARA["dn19"]["vi"]["dn19:source"] =
  "Dịch từ nguồn Pali https://suttacentral.net/";
